  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('--')) {
      result._.push(arg)
      i++
    } else if (arg.includes('=')) {
      // --key=value syntax
      const eqIndex = arg.indexOf('=')
      const key = arg.slice(2, eqIndex)
      const value = arg.slice(eqIndex + 1)
      result[key] = value
      i++
    } else {
      // --key without equals
      const key = arg.slice(2)
      const next = argv[i + 1]
      if (next && next.startsWith('--')) {
        // next arg is a flag, not a value
        result[key] = true
        i++
      } else if (next) {
        // next arg is the value for this key
        result[key] = next
        i += 2
      } else {
        // flag with no value following
        result[key] = true
        i++
      }
    }
  }
  return result
}

